/**
 * Command-line front-end to launch BTestCase or JUnit3/JUnit4 ClassConcept without need for MPS instance/environment
 * XXX Unfortunate name, no idea what 'default' refers to. Now, 'TestExecutor' suffix doesn't make much sense either.
 *     This is merely an POJO main to launch tests in a given mode.
 * FIXME assumes executor classes are in classpath and share CP with that of this class (to take TestExecutor.class parameter)
 *       Proper implementation shall pick JUnit4/5 main() right away at the caller (i.e. DTE has to be split into 2, and placed into different modules), 
 *       so that this class could have proper dependencies.
 * FIXME instead of looking into -junit5 option, could have 2 distinct main() and make decision which one to invoke based on TestParameters
 */
public class DefaultTestExecutor {
  public static final int EXIT_CODE_FOR_EXCEPTION = -12345;

  public DefaultTestExecutor() {
  }

  /**
   * Called when BTestCase or JUnit5 ClassConcept is executed without need for MPS instance/environment
   */
  public static void main(String[] args) throws Exception {
    // FIXME ATM, JUnit5TestExecutor lives in MPS-managed unitTest.execution module, and here we rely on fact its jar is in CP and, more important, works fine w/o MPS classloading.
    //      which is plain wrong use of MPS CL subsystem (e.g. junit5 libraries get here through transitive dependencies from completely another plugin, [mps-testing])
    Class<?> cls = Class.forName("jetbrains.mps.baseLanguage.unitTest.execution.server.JUnit5TestExecutor");
    Constructor<?> ctor = cls.getConstructor(TestsContributor.class, boolean.class, Supplier.class);
    Supplier<ClassLoader> getCL = () -> Thread.currentThread().getContextClassLoader();

    CommandLineTestContributor tc = new CommandLineTestContributor(args);
    final TestExecutor exec = (TestExecutor) ctor.newInstance(tc, true, getCL);

    runAndQuit(exec);
  }

  /*package*/ static void runAndQuit(TestExecutor exec) {
    int exitCode = EXIT_CODE_FOR_EXCEPTION;
    try {
      try {
        exec.init();
        exec.execute();
      } finally {
        Throwable executionError = exec.getExecutionError();
        if (executionError != null) {
          exitCode = EXIT_CODE_FOR_EXCEPTION;
        } else {
          exitCode = exec.getFailureCount();
        }
        exec.dispose();
      }
    } finally {
      System.exit(exitCode);
    }
  }

  /*package*/ static class CommandLineTestContributor implements TestsContributor {
    private final String[] myArgs;

    /*package*/ CommandLineTestContributor(String[] args) {
      myArgs = args;
    }

    @Override
    public Iterable<Request> gatherTests() throws Exception {
      throw new UnsupportedOperationException();
    }
    @Override
    public boolean newAPI() {
      return true;
    }
    @Override
    public Iterable<ExecutorScript.TestRecord> tests() throws Exception {
      //  for command-line, we put all tests into a single fake "" module
      ExecutorScript.TestRecord rv = new ExecutorScript.TestRecord("");
      String[] inlined = inlineFilesContents(myArgs);
      int i = 0;
      while (i < inlined.length) {
        if ("-c".equals(inlined[i])) {
          i++;
          rv.add(inlined[i], "", String.valueOf(true));
        } else
        if ("-m".equals(inlined[i])) {
          i++;
          rv.add(inlined[i], "", String.valueOf(false));
        }
        i++;
      }
      return Collections.singleton(rv);
    }

    @Override
    public ClassLoader classLoader(ExecutorScript.TestRecord tr) throws Exception {
      return getClass().getClassLoader();
    }

    private static String[] inlineFilesContents(String[] args) throws IOException {
      List<String> newArgs = new LinkedList<>();
      //  FIXME ++num, really? Streams?
      for (int num = 0; num < args.length; ++num) {
        String curArg = args[num];
        if ("-f".equals(curArg)) {
          String filename = args[num++];
          // FIXME replace with Files.lines()
          List<String> fileContents = parseRequestFromFile(filename);
          newArgs.addAll(fileContents);
        } else {
          newArgs.add(curArg);
        }
      }
      return newArgs.toArray(new String[newArgs.size()]);
    }

    private static List<String> parseRequestFromFile(@NotNull String filename) throws IOException {
      // FIXME deleteOnExit is caller responsibility
      LineNumberReader reader = new LineNumberReader(new FileReader(filename));
      List<String> fileContents = new ArrayList<String>();
      while (true) {
        String line = reader.readLine();
        if (line == null) {
          break;
        }
        if (!(line.isEmpty())) {
          fileContents.add(line);
        }
      }
      return fileContents;
    }
  }
}
